var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하암-","JPN":"ふぁー","ENG":"*Yawn*","TWN":"哈啊～"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"오늘은 더 이상 지원자가 없나?","JPN":"今日の支援者はこれで終わりか？","ENG":"No more applicants for today?","TWN":"沒有人要來報名了嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이제 그만 돌아가요, 선장니임~","JPN":"もう帰りましょう、船長～","ENG":"Let's head back, Caaaaptain!","TWN":"我們回去吧，船長～"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"배도 고프고 비도 내리기 시작해서 완전 축축하다고요.","JPN":"お腹も空いてきましたし、雨も降ってびしょ濡れですわよ。","ENG":"I'm hungry, and it started raining so I'm all wet now.","TWN":"肚子好餓，而且又開始下雨，身體都淋溼了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"마감시간이 남았으니 좀 참아.","JPN":"締め切りはもう少し後だから我慢しろ。","ENG":"We still have a bit of time before we close up for today.","TWN":"還沒到截止時間，再忍耐一下。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"진정한 동료는 추위와 배고픔 같은 시련 속에서 만나는 법이라고.","JPN":"真の仲間とは寒さや空腹のような試練の中で出会えるもんだ。","ENG":"You have to overcome hardships like the cold and hunger to meet a true crew mate.","TWN":"真正的夥伴就是在飢寒交迫之時產生的。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"히이잉-","JPN":"ふえーん","ENG":"Hhhnnnggg...","TWN":"嗚嗚嗚。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"애초에 입단 조건이 너무 까다로운 거 아녜요?","JPN":"そもそも入団条件が厳しすぎませんか？","ENG":"Don't you think the requirements are too restrictive?","TWN":"不過入團條件是不是有點嚴苛？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"사진 찍히는 거 좋아하고, 급료도 안 받는 호구 지원자가 세상에 존재할 리가…","JPN":"写真を撮られるのが好きで、給料もいらないというおバカな支援者など、この世に存在するはずが……","ENG":"What idiot would apply for a job where they don't get paid but must enjoy having their picture taken?","TWN":"要喜歡拍照，還不拿薪水，世界上有這種人嗎…"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NONAME","text":{"KOREA":"당신들이 프론트베이 샤크스야?","JPN":"あなたたちがフロントベイシャークス？","ENG":"Are you the Front Bay Sharks?","TWN":"你們是前灣大白鯊？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"오? 우리 전단지를 가지고 있구만.","JPN":"お？　うちのチラシを持っているな。","ENG":"Oh? I see you have our flyer over there.","TWN":"嗯？你有拿到我們的傳單喔？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"해적이 되고 싶어?","JPN":"海賊になりたいか？","ENG":"You wanna be a pirate, do ya?","TWN":"你想當海盜？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NONAME","text":{"KOREA":"일단 그렇긴 한데.","JPN":"一応そうだけど。","ENG":"Yes, for now.","TWN":"就當作是吧。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NONAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NONAME","text":{"KOREA":"선실에 아직 자리 남아 있어?","JPN":"船室にまだ席は残っているのか？","ENG":"Do you still have room left in your cabins?","TWN":"船艙還有位置嗎？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"부함장, 우리가 남는 선실이 얼마나 있더라?","JPN":"副艦長、船室は何席残っている？","ENG":"First mate, how many empty cabins do we have left?","TWN":"副船長，我們還剩多少船艙？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"딱 한 자리 남았습니다요!","JPN":"ちょうど一つ残っています！","ENG":"We have room for exactly one!","TWN":"就只剩下一個！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이야- 거 운이 좋구만, 신참.","JPN":"いや～運がいいな、新入り。","ENG":"Whew, you're lucky, rookie.","TWN":"哇，新人，算你幸運！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"하지만, 그 전에 네 적성이 여기에 맞을지 몇 가지 확인이 필요한데-","JPN":"だが、その前にお前の適性がうちと合っているのか、いくつか確認せねばー","ENG":"But first, I have some questions to check if you're the right fit for our crew.","TWN":"不過在你正式加入前，必須再問你幾個問題。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NONAME","text":{"KOREA":"바다에 나갈 수만 있다면 좋아.","JPN":"海に出られるなら構わない。","ENG":"I'm fine, as long as I get to go out to the sea.","TWN":"只要能出海，我什麼都願意做。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"첫번째- 지금 네가 지금 들고 있는 건 뭐지?","JPN":"一つ目、今お前が持っているそれは何だ？","ENG":"First. What's that in your hands?","TWN":"第一題，你現在手裡拿的是什麼？"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NONAME","text":{"KOREA":"화분.","JPN":"植木鉢。","ENG":"A pot.","TWN":"花盆。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NONAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};